	delete(ns.stores, nodeID)
	delete(ns.partitions, nodeID)
	for _, blocked := range ns.partitions {
		delete(blocked, nodeID)
	}
	ns.recordEvent(Event{
		Time:   ns.clock,
		Type:   EventNodeLeave,
		Source: nodeID,
	})
}

