func TestDeque_ConcurrentPushPopAndSteal(t *testing.T) {
	const total = 1000
	const consumers = 8

	d := NewDeque()
	start := make(chan struct{})
	donePushing := make(chan struct{})
	got := make(chan int, total)

	var wg sync.WaitGroup
	wg.Add(1)
	go func() {
		defer wg.Done()
		<-start
		for i := 0; i < total; i++ {
			d.PushBottom(i)
		}
		close(donePushing)
	}()

	for i := 0; i < consumers; i++ {
		wg.Add(1)
		i := i
		go func() {
			defer wg.Done()
			<-start
			for {
				var item interface{}
				var ok bool
				if i%2 == 0 {
					item, ok = d.PopBottom()
				} else {
					item, ok = d.StealTop()
				}
				if ok {
					got <- item.(int)
					continue
				}

				select {
				case <-donePushing:
					if d.IsEmpty() {
						return
					}
				default:
				}
				runtime.Gosched()
			}
		}()
	}

	close(start)
	wg.Wait()
	close(got)

	seen := make([]bool, total)
	count := 0
	for item := range got {
		if item < 0 || item >= total {
			t.Fatalf("unexpected item %d", item)
		}
		if seen[item] {
			t.Fatalf("duplicate item %d", item)
		}
		seen[item] = true
		count++
	}
	if count != total {
		t.Fatalf("expected %d items, got %d", total, count)
	}
}

