func TestSWIM_HistoryEvictsOldEntriesPastLimit(t *testing.T) {
	ml := NewMemberList("n1")
	ml.Alive("n2", 0, nil)
	cfg := DefaultSWIMConfig()
	sd := NewSWIMDetector(ml, cfg, alwaysAck, alwaysNackIndirect, 42)

	for i := 0; i < defaultProbeHistoryLimit; i++ {
		sd.RunProbeRound()
	}
	h := sd.History()
	if len(h) != defaultProbeHistoryLimit {
		t.Fatalf("expected history at cap %d, got %d", defaultProbeHistoryLimit, len(h))
	}
	if h[0].Round != 1 {
		t.Fatalf("expected oldest round 1 at cap, got %d", h[0].Round)
	}
	if h[len(h)-1].Round != defaultProbeHistoryLimit {
		t.Fatalf("expected newest round %d at cap, got %d", defaultProbeHistoryLimit, h[len(h)-1].Round)
	}

	sd.RunProbeRound()
	h = sd.History()
	if len(h) != defaultProbeHistoryLimit {
		t.Fatalf("expected capped history length %d, got %d", defaultProbeHistoryLimit, len(h))
	}
	if h[0].Round != 2 {
		t.Fatalf("expected oldest round 2 after eviction, got %d", h[0].Round)
	}
	if h[len(h)-1].Round != defaultProbeHistoryLimit+1 {
		t.Fatalf("expected newest round %d after eviction, got %d", defaultProbeHistoryLimit+1, h[len(h)-1].Round)
	}
}
	t.Fatal("merkle sync should achieve convergence")
}

