   284	func (ns *NetworkSim) recordEvent(event Event) {
   285		ns.events = append(ns.events, event)
   286		if len(ns.events) <= defaultEventLogLimit {
   287			return
   288		}
   289		excess := len(ns.events) - defaultEventLogLimit
   290		copy(ns.events, ns.events[excess:])
   291		for i := defaultEventLogLimit; i < len(ns.events); i++ {
   292			ns.events[i] = Event{}
   293		}
   294		ns.events = ns.events[:defaultEventLogLimit]
   295	}
