   297	// Converged checks if all nodes have the same state hash.
   298	func (ns *NetworkSim) Converged() bool {
   299		ns.mu.Lock()
   300		defer ns.mu.Unlock()
   301		var firstHash [32]byte
   302		first := true
   303		for _, store := range ns.stores {
   304			h := store.Hash()
   305			if first {
   306				firstHash = h
   307				first = false
   308			} else if h != firstHash {
   309				return false
   310			}
   311		}
   312		return true
   313	}
