   294		got := make(chan int, total)
   295	
   296		var wg sync.WaitGroup
   297		wg.Add(1)
   298		go func() {
   299			defer wg.Done()
   300			<-start
   301			for i := 0; i < total; i++ {
   302				d.PushBottom(i)
   303			}
   304			close(donePushing)
   305		}()
   306	
   307		for i := 0; i < consumers; i++ {
   308			wg.Add(1)
   309			i := i
   310			go func() {
   311				defer wg.Done()
   312				<-start
   313				for {
   314					var item interface{}
   315					var ok bool
   316					if i%2 == 0 {
   317						item, ok = d.PopBottom()
   318					} else {
   319						item, ok = d.StealTop()
   320					}
   321					if ok {
   322						got <- item.(int)
   323						continue
   324					}
   325	
   326					select {
   327					case <-donePushing:
   328						if d.IsEmpty() {
   329							return
   330						}
   331					default:
   332					}
   333					runtime.Gosched()
   334				}
   335			}()
   336		}
   337	
   338		close(start)
   339		wg.Wait()
   340		close(got)
